UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "HVAC - Services Overview", "content": "Welcome to our hvac business. We provide heating, ventilation, and air conditioning services including AC repair, furnace installation, heat pump service, ductwork, indoor air quality, thermostat installation, and preventive maintenance plans. Emergency 24/7 service available for no-heat and no-cool situations.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "HVAC - Pricing & Process", "content": "Our pricing approach for hvac: Most diagnostic visits are $89-$149. Repairs typically range $200-$800. New system installation starts around $5,500. We offer financing options and free estimates on replacements. Maintenance plans start at $189/year.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "How often should I service my HVAC system?", "answer": "We recommend twice a year - heating tune-up in fall and AC tune-up in spring.", "category": "general"}, {"question": "How long does a new system last?", "answer": "A well-maintained AC lasts 12-15 years; furnaces 15-20 years.", "category": "general"}, {"question": "Do you offer financing?", "answer": "Yes, we offer 0% APR financing on qualifying installations.", "category": "general"}, {"question": "Are you licensed and insured?", "answer": "Yes, fully licensed, bonded, and insured. EPA 608 certified technicians.", "category": "general"}, {"question": "Do you provide emergency service?", "answer": "Yes, 24/7 emergency service for no-heat and no-cool situations.", "category": "general"}]}, {"name": "HVAC - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: How often should I service my HVAC system?\nA: We recommend twice a year - heating tune-up in fall and AC tune-up in spring.\n\nQ: How long does a new system last?\nA: A well-maintained AC lasts 12-15 years; furnaces 15-20 years.\n\nQ: Do you offer financing?\nA: Yes, we offer 0% APR financing on qualifying installations.\n\nQ: Are you licensed and insured?\nA: Yes, fully licensed, bonded, and insured. EPA 608 certified technicians.\n\nQ: Do you provide emergency service?\nA: Yes, 24/7 emergency service for no-heat and no-cool situations."}]'::jsonb, updated_at = now() WHERE industry_id = 'hvac';
UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "Plumbing - Services Overview", "content": "Welcome to our plumbing business. Full-service plumbing including drain cleaning, water heater repair and installation, leak detection, pipe repair/repipe, fixture installation, sewer line service, sump pumps, and water filtration. Available 24/7 for emergencies.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "Plumbing - Pricing & Process", "content": "Our pricing approach for plumbing: Service call $79-$149. Drain cleaning from $179. Water heater install $1,200-$2,800. Free estimates on major repairs. Upfront flat-rate pricing - no surprises.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "Do you charge for estimates?", "answer": "Free estimates on installations; diagnostic fee for service calls is credited toward repair.", "category": "general"}, {"question": "How fast can you respond to emergencies?", "answer": "Most emergencies within 1-2 hours, 24/7.", "category": "general"}, {"question": "Do you offer warranties?", "answer": "Yes, 1-year labor warranty on most repairs and manufacturer warranty on parts.", "category": "general"}, {"question": "Can you handle gas line work?", "answer": "Yes, our techs are certified for gas line installation and repair.", "category": "general"}, {"question": "What payment methods do you accept?", "answer": "Cash, all major cards, and financing through approved lenders.", "category": "general"}]}, {"name": "Plumbing - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: Do you charge for estimates?\nA: Free estimates on installations; diagnostic fee for service calls is credited toward repair.\n\nQ: How fast can you respond to emergencies?\nA: Most emergencies within 1-2 hours, 24/7.\n\nQ: Do you offer warranties?\nA: Yes, 1-year labor warranty on most repairs and manufacturer warranty on parts.\n\nQ: Can you handle gas line work?\nA: Yes, our techs are certified for gas line installation and repair.\n\nQ: What payment methods do you accept?\nA: Cash, all major cards, and financing through approved lenders."}]'::jsonb, updated_at = now() WHERE industry_id = 'plumbing';
UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "Electrical - Services Overview", "content": "Welcome to our electrical business. Licensed electrical services: panel upgrades, EV charger installation, lighting, outlets/switches, ceiling fans, generator installation, whole-home surge protection, code-compliance inspections, and 24/7 emergency repair.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "Electrical - Pricing & Process", "content": "Our pricing approach for electrical: Diagnostic $99-$159. Outlet/switch install from $150. Panel upgrade $1,800-$4,500. EV charger install $600-$1,800. Free estimates on major work.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "Are your electricians licensed?", "answer": "Yes, all work performed by licensed electricians and inspected for code compliance.", "category": "general"}, {"question": "Do you pull permits?", "answer": "Yes, we handle all permits required by your local jurisdiction.", "category": "general"}, {"question": "Can you install an EV charger?", "answer": "Yes, we install Level 2 chargers for all major EV brands.", "category": "general"}, {"question": "Do you do generator installs?", "answer": "Yes, including whole-home Generac and Kohler standby generators.", "category": "general"}, {"question": "How do I know if I need a panel upgrade?", "answer": "If you have a fuse box, frequent breaker trips, or are adding major appliances/EV - schedule an evaluation.", "category": "general"}]}, {"name": "Electrical - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: Are your electricians licensed?\nA: Yes, all work performed by licensed electricians and inspected for code compliance.\n\nQ: Do you pull permits?\nA: Yes, we handle all permits required by your local jurisdiction.\n\nQ: Can you install an EV charger?\nA: Yes, we install Level 2 chargers for all major EV brands.\n\nQ: Do you do generator installs?\nA: Yes, including whole-home Generac and Kohler standby generators.\n\nQ: How do I know if I need a panel upgrade?\nA: If you have a fuse box, frequent breaker trips, or are adding major appliances/EV - schedule an evaluation."}]'::jsonb, updated_at = now() WHERE industry_id = 'electrical';
UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "Roofing - Services Overview", "content": "Welcome to our roofing business. Residential and commercial roofing: full roof replacement, repair, leak detection, gutter installation, skylight install, storm damage repair, and insurance claim assistance. Asphalt, metal, tile, and flat roofing.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "Roofing - Pricing & Process", "content": "Our pricing approach for roofing: Free roof inspections. Repairs from $350. Full asphalt replacement $8,000-$18,000 typical. We work with most insurance carriers on storm damage claims.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "Do you offer free inspections?", "answer": "Yes, free no-obligation roof inspections including drone imagery.", "category": "general"}, {"question": "How long does a roof replacement take?", "answer": "Most homes are completed in 1-2 days.", "category": "general"}, {"question": "Do you help with insurance claims?", "answer": "Yes, we assist with documentation, adjuster meetings, and claim filing.", "category": "general"}, {"question": "What warranty do you offer?", "answer": "Up to 50-year material warranty plus 10-year workmanship warranty.", "category": "general"}, {"question": "Can you repair instead of replace?", "answer": "Often yes - we''ll always recommend the most cost-effective option.", "category": "general"}]}, {"name": "Roofing - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: Do you offer free inspections?\nA: Yes, free no-obligation roof inspections including drone imagery.\n\nQ: How long does a roof replacement take?\nA: Most homes are completed in 1-2 days.\n\nQ: Do you help with insurance claims?\nA: Yes, we assist with documentation, adjuster meetings, and claim filing.\n\nQ: What warranty do you offer?\nA: Up to 50-year material warranty plus 10-year workmanship warranty.\n\nQ: Can you repair instead of replace?\nA: Often yes - we''ll always recommend the most cost-effective option."}]'::jsonb, updated_at = now() WHERE industry_id = 'roofing';
UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "Appliance Repair - Services Overview", "content": "Welcome to our appliance repair business. Repair for refrigerators, washers, dryers, dishwashers, ovens, ranges, microwaves, garbage disposals, and ice makers. All major brands. Same-day service when possible.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "Appliance Repair - Pricing & Process", "content": "Our pricing approach for appliance repair: Service call $89 (waived with repair). Most repairs $150-$400. 90-day parts and labor warranty.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "What brands do you service?", "answer": "All major brands: Whirlpool, GE, Samsung, LG, Maytag, KitchenAid, Bosch, Sub-Zero, Viking, and more.", "category": "general"}, {"question": "Is it worth repairing?", "answer": "Generally yes if repair is under 50% of replacement cost and appliance is under 8 years old.", "category": "general"}, {"question": "Do you stock common parts?", "answer": "Yes, our trucks carry parts for the most common repairs - many fixed in one visit.", "category": "general"}, {"question": "Do you offer same-day service?", "answer": "Yes, when scheduled before noon, subject to availability.", "category": "general"}, {"question": "What''s your warranty?", "answer": "90-day warranty on parts and labor.", "category": "general"}]}, {"name": "Appliance Repair - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: What brands do you service?\nA: All major brands: Whirlpool, GE, Samsung, LG, Maytag, KitchenAid, Bosch, Sub-Zero, Viking, and more.\n\nQ: Is it worth repairing?\nA: Generally yes if repair is under 50% of replacement cost and appliance is under 8 years old.\n\nQ: Do you stock common parts?\nA: Yes, our trucks carry parts for the most common repairs - many fixed in one visit.\n\nQ: Do you offer same-day service?\nA: Yes, when scheduled before noon, subject to availability.\n\nQ: What''s your warranty?\nA: 90-day warranty on parts and labor."}]'::jsonb, updated_at = now() WHERE industry_id = 'appliance_repair';
UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name": "Pest Control - Services Overview", "content": "Welcome to our pest control business. General pest, termites, bed bugs, rodents, mosquitos, ants, roaches, spiders, wasps. Eco-friendly options. Quarterly maintenance plans and one-time treatments.\n\nServing residential and commercial customers with licensed, insured, and experienced professionals."}, {"name": "Pest Control - Pricing & Process", "content": "Our pricing approach for pest control: Initial treatment $150-$350. Quarterly plans from $99/quarter. Termite inspections free; treatment varies by infestation.\n\nProcess: 1) Schedule a consultation or service visit. 2) Receive a detailed quote upfront. 3) Approve and we get to work. 4) Follow up to confirm satisfaction.", "faqs": [{"question": "Are treatments safe for pets and kids?", "answer": "Yes, we use EPA-approved products and let you know when areas are safe to re-enter.", "category": "general"}, {"question": "How long does treatment take?", "answer": "Most treatments are 30-60 minutes.", "category": "general"}, {"question": "Do you offer guarantees?", "answer": "Yes, free re-treatment if pests return between scheduled visits.", "category": "general"}, {"question": "What''s the best plan for my home?", "answer": "Quarterly preventive treatments are most cost-effective for ongoing protection.", "category": "general"}, {"question": "Do you do termite inspections for real estate?", "answer": "Yes, we provide WDO/WDI reports for home sales.", "category": "general"}]}, {"name": "Pest Control - Frequently Asked Questions", "content": "Here are common questions and answers about our services:\n\nQ: Are treatments safe for pets and kids?\nA: Yes, we use EPA-approved products and let you know when areas are safe to re-enter.\n\nQ: How long does treatment take?\nA: Most treatments are 30-60 minutes.\n\nQ: Do you offer guarantees?\nA: Yes, free re-treatment if pests return between scheduled visits.\n\nQ: What''s the best plan for my home?\nA: Quarterly preventive treatments are most cost-effective for ongoing protection.\n\nQ: Do you do termite inspections for real estate?\nA: Yes, we provide WDO/WDI reports for home sales."}]'::jsonb, updated_at = now() WHERE industry_id = 'pest_control';
